import{_ as a,o as d,c as o,j as e,a as s,t as r,ai as n,aj as i}from"./chunks/framework.D5dNhNW5.js";const m=JSON.parse('{"title":"进阶配置","description":"","frontmatter":{"title":"进阶配置"},"headers":[],"relativePath":"zh/usage/config.md","filePath":"zh/usage/config.md"}'),g={name:"zh/usage/config.md"},c={id:"frontmatter-title",tabindex:"-1"};function f(l,t,h,x,p,y){return d(),o("div",null,[e("h1",c,[s(r(l.$frontmatter.title)+" ",1),t[0]||(t[0]=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),t[1]||(t[1]=n('<p>你可以通过游戏内 ModConfig 的可视化界面自由调整所有电击参数和连接行为。</p><div class="caution custom-block github-alert"><p class="custom-block-title">安全须知</p><p>所有的“最低强度”和“电击上限”的基准，<strong>都取决于你在郊狼 APP 内手动拉高的通道上限</strong>。所以第一道安全防线始终是你手机里的上限设置！</p></div><h2 id="基础连接设置" tabindex="-1">基础连接设置 <a class="header-anchor" href="#基础连接设置" aria-label="Permalink to “基础连接设置”">​</a></h2><ul><li><strong>端口号</strong>：WebSocket 服务器监听的端口。修改此项后需要重新刷新二维码。</li><li><strong>绑定 IP 地址</strong>：默认绑定在你可访问互联网的网卡的局域网地址。留空即可。如需搭配内网穿透进行远程控制，可手动指定。</li><li><strong>最大连接数</strong>：允许同时连接的 APP 数量（默认 <code>8</code>）。</li><li><strong>显示二维码</strong> / <strong>断开所有连接</strong>：推荐绑定趁手的快捷键！</li></ul><h2 id="电击设置与调参建议" tabindex="-1">电击设置与调参建议 <a class="header-anchor" href="#电击设置与调参建议" aria-label="Permalink to “电击设置与调参建议”">​</a></h2><p><img src="'+i+'" alt="伤害与强度关系图"></p><p>默认参数（<code>最低强度=5</code>, <code>伤害上限=25</code>）属于偏保守的设计，十分适合第一次体验的玩家。你可以根据郊狼 App 里设置的通道强度上限，来调整这些数值以适应你想要的风格：</p><ul><li><strong>最低强度</strong>：建议设为 <code>App 通道上限 × 5%</code>（能感觉到但不刺激的起跳值）。</li><li><strong>伤害上限 (Damage Cap)</strong>：电球造成大于此伤害后，将不再提升电流强度。</li></ul><p><strong>伤害上限风格参考表：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">风格</th><th style="text-align:left;">伤害上限推荐值</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>温和</strong></td><td style="text-align:left;"><code>30</code></td><td style="text-align:left;">适合长时间轻度休闲游玩，很难达到最高电击。</td></tr><tr><td style="text-align:left;"><strong>标准</strong></td><td style="text-align:left;"><code>20~25</code></td><td style="text-align:left;">默认推荐，伤害曲线平衡。</td></tr><tr><td style="text-align:left;"><strong>激进</strong></td><td style="text-align:left;"><code>12~15</code></td><td style="text-align:left;">追求刺激！低伤害也能电得很有感。</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">典型伤害参考（25 上限时）</p><p></p><ul><li><code>3 点伤害</code> 占比约 <code>50%</code> （无集中被动）</li><li><code>8 点伤害</code> 占比约 <code>71%</code> （无集中激发）</li><li><code>11 点伤害</code> 占比约 <code>78%</code> （3 层集中激发）</li></ul></div><h2 id="波形选择" tabindex="-1">波形选择 <a class="header-anchor" href="#波形选择" aria-label="Permalink to “波形选择”">​</a></h2><p>你可以为单独的 A 通道和 B 通道分别配置启用不同波形。我们预设了多款官方经典波形：</p><table tabindex="0"><thead><tr><th style="text-align:left;">波形名称</th><th style="text-align:left;">内部标识</th><th style="text-align:left;">适用场景 / 备注</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>呼吸</strong></td><td style="text-align:left;">Breath</td><td style="text-align:left;">经典呼吸，12 组循环</td></tr><tr><td style="text-align:left;"><strong>潮汐</strong></td><td style="text-align:left;">Tide</td><td style="text-align:left;">为短促电击精简，连绵起伏</td></tr><tr><td style="text-align:left;"><strong>连击</strong></td><td style="text-align:left;">Batter</td><td style="text-align:left;">为短促电击精简，强打击感</td></tr><tr><td style="text-align:left;"><strong>快速按捏</strong></td><td style="text-align:left;">Pinch</td><td style="text-align:left;">为短促电击精简，高频次</td></tr><tr><td style="text-align:left;"><strong>按捏渐强</strong></td><td style="text-align:left;">PinchRamp</td><td style="text-align:left;">渐强按捏，适合高伤</td></tr><tr><td style="text-align:left;"><strong>心跳节奏</strong></td><td style="text-align:left;">Heartbeat</td><td style="text-align:left;">模拟心跳</td></tr><tr><td style="text-align:left;"><strong>压缩</strong></td><td style="text-align:left;">Squeeze</td><td style="text-align:left;">为短促电击精简</td></tr><tr><td style="text-align:left;"><strong>节奏步伐</strong></td><td style="text-align:left;">Rhythm</td><td style="text-align:left;">为短促电击精简</td></tr></tbody></table><h3 id="自定义波形扩展" tabindex="-1">自定义波形扩展 <a class="header-anchor" href="#自定义波形扩展" aria-label="Permalink to “自定义波形扩展”">​</a></h3><p>如果没有满意的波形，你可以通过添加波形文件来扩展！</p><ol><li>确保 Mod 至少启动过一次，会自动创建文件夹。</li><li>前往游戏 Mod 目录下的 <code>TazeU/waveforms/</code> 文件夹。</li><li>创建或放入 <code>.jsonc</code> 格式的 V3 波形数据。</li><li><strong>重启游戏</strong>即可在波形下拉菜单中使用你的自定义波形！</li></ol><div class="tip custom-block github-alert"><p class="custom-block-title">自定义格式</p><p>JSONC 格式非常简单，只需包含 <code>name</code> 字段（下拉菜单显示名称）和 <code>data</code> 数组。具体 V3 波形的十六进制编码细节可参见<a href="https://github.com/DG-LAB-OPENSOURCE/DG-LAB-OPENSOURCE/tree/main/coyote/extra" target="_blank" rel="noreferrer">郊狼官方协议文档</a>。</p></div><p>出于体验建议，自定义的波形长度不要超过 15 组（即 1.5 秒），过长的波形可能会导致电击体验不够紧凑，尤其是在频繁触发的战斗中。</p>',19))])}const u=a(g,[["render",f]]);export{m as __pageData,u as default};
